mapper.select:
SELECT id, file_name, store_key, file_type, business_type, file_path, file_size, content_type, description, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_file WHERE is_deleted = 0
AND file_type = #{fileType}
AND file_name LIKE CONCAT('%', #{fileName}, '%')
AND business_type = #{businessType}
ORDER BY create_date DESC

mapper.update:
UPDATE sp_file
file_name = #{fileName}, business_type = #{businessType}, description = #{description}, update_name = #{updateName}, update_id = #{updateId},
WHERE id = #{id}
